<template>
  <div class="store-container">
    <!-- 顶部导航栏 -->
    <el-header class="store-header">
      <div class="header-content">
        <div class="store-info">
          <span class="store-name">{{ storeName }}</span>
          <el-tag type="success">营业中</el-tag>
        </div>
        <el-button type="danger" @click="handleLogout">退出登录</el-button>
      </div>
    </el-header>

    <el-main class="store-main">
      <!-- 操作工具栏 -->
      <div class="toolbar">
        <el-button type="primary" @click="showAddDialog">+ 新增商品</el-button>
        <el-input
            v-model="searchKeyword"
            placeholder="搜索商品名称"
            class="search-input"
            clearable
        >
          <template #prefix>
            <el-icon><Search /></el-icon>
          </template>
        </el-input>
      </div>

      <!-- 商品列表 -->
      <el-row :gutter="20" class="product-list">
        <el-col
            v-for="product in filteredProducts"
            :key="product.id"
            :xs="24" :sm="12" :md="8" :lg="6"
        >
          <el-card class="product-card">
            <el-image
                :src="product.image"
                fit="cover"
                class="product-image"
                :preview-src-list="[product.image]"
            />
            <div class="product-info">
              <h3 class="product-title">{{ product.name }}</h3>
              <div class="product-meta">
                <span class="price">¥ {{ product.price }}</span>
                <span class="stock">库存 {{ product.quantity }}</span>
              </div>
              <p class="product-desc">{{ product.description }}</p>
              <div class="product-actions">
                <el-button type="primary" size="small" @click="editProduct(product)">编辑</el-button>
                <el-button
                    :type="product.status ? 'success' : 'warning'"
                    size="small"
                    @click="toggleStatus(product)"
                >
                  {{ product.status ? '下架' : '上架' }}
                </el-button>
              </div>
            </div>
          </el-card>
        </el-col>
      </el-row>

      <!-- 商品编辑对话框 -->
      <el-dialog
          v-model="showDialog"
          :title="isEditing ? '编辑商品' : '新增商品'"
          width="600px"
      >
        <el-form :model="currentProduct" label-width="80px">
          <el-form-item label="商品名称" required>
            <el-input v-model="currentProduct.name" />
          </el-form-item>

          <el-form-item label="价格" required>
            <el-input-number
                v-model="currentProduct.price"
                :min="0.01"
                :precision="2"
                :step="1"
            />
          </el-form-item>

          <el-form-item label="库存" required>
            <el-input-number v-model="currentProduct.quantity" :min="0" />
          </el-form-item>
          <!-- 新增分类选择 -->
          <el-form-item label="商品分类" required>
            <el-select
                v-model="currentProduct.sort"
                placeholder="请选择分类"
                style="width: 100%"
            >
              <el-option
                  v-for="item in productCategories"
                  :key="item.value"
                  :label="item.label"
                  :value="item.value"
              />
            </el-select>
          </el-form-item>

          <el-form-item label="商品描述">
            <el-input
                v-model="currentProduct.description"
                type="textarea"
                :rows="3"
            />
          </el-form-item>

          <el-form-item label="商品图片" required>
            <el-upload
                list-type="picture-card"
                :limit="1"
                :file-list="fileList"
                :before-upload="beforeUpload"
                :on-change="handleFileChange"
                :auto-upload="false"
            >
              <el-icon><Plus /></el-icon>
            </el-upload>
          </el-form-item>

          <el-form-item label="商品状态">
            <el-switch
                v-model="currentProduct.status"
                active-text="上架"
                inactive-text="下架"
            />
          </el-form-item>
        </el-form>

        <template #footer>
          <el-button @click="showDialog = false">取消</el-button>
          <el-button type="primary" @click="submitProduct">确认</el-button>
        </template>
      </el-dialog>
    </el-main>
  </div>
</template>

<script setup>
import { ref, computed, onMounted } from 'vue'
import { ElMessage } from 'element-plus'
import { useRouter } from 'vue-router'
import {parseToken} from "@/Utils/auth";
const router = useRouter()

// 店铺信息
const storeName = ref(localStorage.getItem("storeName")|| '我的店铺')
const searchKeyword = ref('')
const showDialog = ref(false)
const isEditing = ref(false)
const fileList = ref([])
const productCategories = [
  { label: '数码电子', value: '1' },
  { label: '服装服饰', value: '2' },
  { label: '家居生活', value: '3' },
  { label: '美妆护肤', value: '4' },
  { label: '图书音像', value: '5' },
  { label: '冷冻生鲜', value: '6' },
]
// 商品数据
const products = ref([])
const currentProduct = ref({
  id: null,
  name: '',
  price: 0,
  quantity: 0,
  sort:'',
  description: '',
  image: '',
  status: true
})

const authStore =() =>{
  console.log("进入store页面")
  try {
    const payload = parseToken(localStorage.getItem('token'));
    if (payload.role !== 'store') router.push('/login')
  }catch (error){
    console.log(`商家页面初始化错误:${error}`)
    router.push('/login')
  }
}

// 获取商品列表
const fetchProducts = async () => {
  try {
    const storeId = localStorage.getItem('storeId') // 获取存储的店铺ID
    const response = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/goods`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ store_id: storeId }) // 添加店铺ID到请求体
    })

    if (!response.ok) throw new Error('获取商品失败')
    products.value = await response.json()
    products.value.forEach((p)=>{
      p.image = `${process.env.VUE_APP_IMG_BASE_URL}/${p.image}`
    })

  } catch (error) {
    ElMessage.error(error.message)
  }
}

// 搜索过滤
const filteredProducts = computed(() => {
  return products.value.filter(p =>
      p.name.toLowerCase().includes(searchKeyword.value.toLowerCase())
  )
})
// 文件引用用于上传
const file = ref(null)
const handleFileChange = (uploadFile) => {
  file.value = uploadFile.raw
}

// 图片上传处理
const beforeUpload = (file) => {
  const isImage = file.type.startsWith('image/')
  const isLt2M = file.size / 1024 / 1024 < 2

  if (!isImage) {
    ElMessage.error('只能上传图片文件')
    return false
  }
  if (!isLt2M) {
    ElMessage.error('图片大小不能超过2MB')
    return false
  }
  return true
}


// 商品操作
const showAddDialog = () => {
  isEditing.value = false
  currentProduct.value = {
    id: null,
    name: '',
    price: 0,
    quantity: 0,
    description: '',
    image: '',
    status: true
  }
  fileList.value = []
  showDialog.value = true
}

const submitProduct = async () => {
  try {
    const formData = new FormData()
    const storeId = localStorage.getItem('storeId')

    // 添加商品公共数据
    formData.append('name', currentProduct.value.name)
    formData.append('price', currentProduct.value.price)
    formData.append('quantity', currentProduct.value.quantity)
    formData.append('sort',currentProduct.value.sort)
    formData.append('shop', storeId || '1') // 使用实际店铺ID

    // 如果是编辑操作，添加商品ID
    if (isEditing.value) {
      formData.append('id', currentProduct.value.id)
    }

    // 添加图片文件（如果有新上传的图片）
    if (file.value) {
      formData.append('image', file.value)
    }

    // 根据是编辑还是新增决定请求的API端点
    const apiUrl = isEditing.value
        ? `${process.env.VUE_APP_API_BASE_URL}/api/goodsUpdate`
        : `${process.env.VUE_APP_API_BASE_URL}/api/goodsInser`

    const response = await fetch(apiUrl, {
      method: 'POST',
      body: formData
    })

    if (!response.ok) throw new Error(isEditing.value ? '更新商品失败' : '添加商品失败')

    ElMessage.success(isEditing.value ? '商品更新成功' : '商品添加成功')
    showDialog.value = false
    await fetchProducts()
  } catch (error) {
    ElMessage.error(error.message)
  }
}

const editProduct = (product) => {
  isEditing.value = true
  currentProduct.value = {
    ...product,
    // 确保数据类型一致
    price: Number(product.price),
    quantity: Number(product.quantity),
    sort: product.sort.toString()
  }
  // 初始化图片列表
  fileList.value = product.image ? [{ url: product.image }] : []
  showDialog.value = true
}



const toggleStatus = async (product) => {
  try {
    // const token = localStorage.getItem('token')
    const newStatus = !product.status

    // await fetch(`http://localhost:8081/api/goods/`, {
    //   method: 'PATCH',
    //   // headers: {
    //   //   'Authorization': `Bearer ${token}`,
    //   //   // 'Content-Type': 'application/json'
    //   // },
    //   body: JSON.stringify({ status: newStatus })
    // })

    product.status = newStatus
    ElMessage.success(`已${newStatus ? '上架' : '下架'}`)
  } catch (error) {
    ElMessage.error('操作失败')
  }
}

// 退出登录
const handleLogout = () => {
  localStorage.removeItem('token')
  localStorage.removeItem('storeId')
  router.push('/login')
}

onMounted(() => {
  authStore()
  fetchProducts()
})
</script>

<style scoped>
.store-container {
  height: 100vh;
  background: linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%);
}

.store-header {
  background: rgba(255,255,255,0.95);
  box-shadow: 0 2px 12px rgba(0,0,0,0.1);
}

.header-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

.store-info {
  display: flex;
  align-items: center;
  gap: 15px;
}

.store-name {
  font-size: 20px;
  font-weight: 600;
  color: #303133;
}

.store-main {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

.toolbar {
  display: flex;
  justify-content: space-between;
  margin-bottom: 20px;
  gap: 20px;
}

.search-input {
  width: 300px;
}

.product-card {
  margin-bottom: 20px;
  transition: transform 0.3s;
}

.product-card:hover {
  transform: translateY(-5px);
}

.product-image {
  width: 100%;
  height: 200px;
  border-radius: 8px;
}

.product-info {
  padding: 15px;
}

.product-title {
  font-size: 16px;
  margin: 0 0 10px;
  color: #303133;
}

.product-meta {
  display: flex;
  justify-content: space-between;
  margin-bottom: 10px;
}

.price {
  color: #f56c6c;
  font-weight: 600;
}

.stock {
  color: #909399;
}

.product-desc {
  color: #606266;
  font-size: 12px;
  line-height: 1.5;
  margin: 10px 0;
}

.product-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 15px;
}

:deep(.el-upload--picture-card) {
  width: 120px;
  height: 120px;
}
</style>