<template>
  <div class="order-container">
    <!-- 顶部导航栏 -->
    <el-header class="order-header">
      <div class="header-content">
        <div class="order-title">
          <span class="title-text">我的订单</span>
          <el-tag type="success">共 {{ totalOrders }} 笔订单</el-tag>
        </div>
        <el-button type="danger" @click="handleLogout">退出登录</el-button>
      </div>
    </el-header>

    <el-main class="order-main">
      <!-- 订单筛选工具栏 -->
      <div class="filter-toolbar">
        <el-radio-group v-model="orderStatus" @change="fetchOrders">
          <el-radio-button label="all">全部订单</el-radio-button>
          <el-radio-button label="pending">待付款</el-radio-button>
          <el-radio-button label="shipped">待发货</el-radio-button>
          <el-radio-button label="delivered">待收货</el-radio-button>
          <el-radio-button label="completed">已完成</el-radio-button>
          <el-radio-button label="cancelled">已取消</el-radio-button>
        </el-radio-group>

        <div class="search-box">
          <el-input
              v-model="searchKeyword"
              placeholder="搜索订单号/商品名称"
              clearable
              class="search-input"
          >
            <template #prefix>
              <el-icon><Search /></el-icon>
            </template>
          </el-input>
          <el-button type="primary" @click="fetchOrders">搜索</el-button>
        </div>
      </div>

      <!-- 订单列表 -->
      <div class="order-list">
        <el-card
            v-for="order in filteredOrders"
            :key="order.id"
            class="order-card"
            :class="{
            'pending-order': order.status === 'pending',
            'shipped-order': order.status === 'shipped',
            'delivered-order': order.status === 'delivered'
          }"
        >
          <div class="order-header">
            <div class="order-meta">
              <span class="order-no">订单号: {{ order.orderNo }}</span>
              <span class="order-time">{{ formatDate(order.create_time) }}</span>
            </div>
            <el-tag :type="getStatusTagType(order.status)">
              {{ getStatusText(order.status) }}
            </el-tag>
          </div>

          <el-divider />

          <div class="order-body">
            <!-- 商品列表 -->
            <div class="product-list">
              <div
                  v-for="item in order.items"
                  :key="item.id"
                  class="product-item"
                  @click="showProductDetail(item)"
              >
                <el-image
                    :src="item.image"
                    fit="cover"
                    class="product-image"
                />
                <div class="product-info">
                  <h4 class="product-name">{{ item.name }}</h4>
                  <div class="product-spec">
                    <span class="spec-text">{{ item.specification }}</span>
                    <span class="quantity">x{{ item.quantity }}</span>
                  </div>
                  <div class="product-price">¥{{ item.price }}</div>
                </div>
              </div>
            </div>

            <el-divider />

            <!-- 订单摘要 -->
            <div class="order-summary">
              <div class="delivery-info">
                <el-icon><Location /></el-icon>
                <span class="delivery-address">{{ order.deliveryAddress }}</span>
              </div>
              <div class="total-amount">
                共 {{ order.items.length }} 件商品 合计:
                <span class="amount">¥{{ order.totalAmount }}</span>
                (含运费 ¥{{ order.shippingFee }})
              </div>
            </div>
          </div>

          <div class="order-footer">
            <el-button
                v-if="order.status === 'pending'"
                type="danger"
                size="small"
                @click="cancelOrder(order)"
            >
              取消订单
            </el-button>
            <el-button
                v-if="order.status === 'pending'"
                type="primary"
                size="small"
                @click="payOrder(order)"
            >
              立即付款
            </el-button>
            <el-button
                v-if="order.status === 'delivered'"
                type="success"
                size="small"
                @click="confirmReceipt(order)"
            >
              确认收货
            </el-button>
            <el-button
                type="text"
                size="small"
                @click="viewOrderDetail(order)"
            >
              查看详情
            </el-button>
          </div>
        </el-card>
      </div>

      <!-- 分页控件 -->
      <div class="pagination">
        <el-pagination
            v-model:current-page="currentPage"
            v-model:page-size="pageSize"
            :total="totalOrders"
            layout="total, prev, pager, next, jumper"
            @current-change="fetchOrders"
        />
      </div>

      <!-- 商品详情对话框 -->
      <el-dialog v-model="showProductDialog" title="商品详情" width="50%">
        <product-detail :product="selectedProduct" />
      </el-dialog>
    </el-main>
  </div>
</template>

<script setup>
import { ref, computed, onMounted } from 'vue'
import { Search, Location } from '@element-plus/icons-vue'
import { useRouter } from 'vue-router'
import ProductDetail from '@/views/ProductDetail.vue'
import {ElMessage} from "element-plus";
import HttpUtils from '@/Utils/HttpRequest'
import {parseToken} from '@/Utils/auth'

const router = useRouter()

// 用户信息
const userId = ref()

// 订单数据
const orders = ref([])
const totalOrders = ref(0)
const currentPage = ref(1)
const pageSize = ref(10)
const orderStatus = ref('all')
const searchKeyword = ref('')

// 对话框控制
const showProductDialog = ref(false)
const selectedProduct = ref(null)

// 获取订单数据
const fetchOrders = async () => {
  try {
    // 从localStorage获取用户ID
    const token = localStorage.getItem('token')
    var payload = parseToken(token);
    if (payload === null || payload.role !== 'user') {
      ElMessage.warning('请先登录')
      router.push('/login')
      return
    }
    userId.value = payload.phone

    // 这里发起POST请求获取订单数据
    const data = await HttpUtils.get(`${process.env.VUE_APP_API_BASE_URL}/api/order/all`,
            {params:{user_id:userId.value}}
    ).then( data =>{
            totalOrders.value = data.data.order_mesg.length
            orders.value = data.data.order_mesg.map(o => ({
              id:`order_${o.order_id}`,
              orderNo:`NO${o.order_id}`,
              deliveryAddress:o.address,
              status:'shipped',
              totalAmount:o.total,
              create_time:o.create_time,
              shippingFee: (Math.random() * 20).toFixed(2),
              items: Array.from(o.goods,g=>({
                id: g.goods_id,
                name: g.name,
                image: `${process.env.VUE_APP_IMG_BASE_URL}/${g.image}`,
                price: g.price,
                quantity: g.count,
              }))
            }))
         console.log(orders.value)
        }
    )
    console.log(data)

  } catch (error) {
    ElMessage.error('获取订单失败: ' + error.message)
    console.error(error)
  }
}

// 订单状态处理
const getStatusTagType = (status) => {
  const map = {
    pending: 'danger',
    shipped: 'warning',
    delivered: 'primary',
    completed: 'success',
    cancelled: 'info'
  }
  return map[status] || 'info'
}

const getStatusText = (status) => {
  const map = {
    pending: '待付款',
    shipped: '待发货',
    delivered: '待收货',
    completed: '已完成',
    cancelled: '已取消'
  }
  return map[status] || '未知状态'
}

// 订单操作
const payOrder = (order) => {
  ElMessage.success(`正在支付订单 ${order.orderNo}`)
  // 实际支付逻辑
}

const cancelOrder = (order) => {
  ElMessage.warning(`取消订单 ${order.orderNo}`)
  // 实际取消逻辑
}

const confirmReceipt = (order) => {
  ElMessage.success(`确认收货 ${order.orderNo}`)
  // 实际确认收货逻辑
}

const viewOrderDetail = (order) => {
  // 跳转到订单详情页
  router.push(`/order/${order.id}`)
}

// 商品详情
const showProductDetail = (product) => {
  selectedProduct.value = product
  showProductDialog.value = true
}

// 格式化日期
// 修改后的日期格式化方法
const formatDate = (dateString) => {
  const options = {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit'
  }
  return new Date(dateString).toLocaleString('zh-CN', options)
}

// 过滤订单
const filteredOrders = computed(() => {
  return orders.value.filter(order => {
    // 状态过滤
    if (orderStatus.value !== 'all' && order.status !== orderStatus.value) {
      console.log("12121")
      return false
    }

    // 关键词搜索
    if (searchKeyword.value) {
      const keyword = searchKeyword.value.toLowerCase()
      return (
          order.orderNo.toLowerCase().includes(keyword) ||
          order.items.some(item => item.name.toLowerCase().includes(keyword))
      )
    }

    return true
  })
})

// 退出登录
const handleLogout = () => {
  localStorage.removeItem('token')
  localStorage.removeItem('userId')
  router.push('/login')
}

// 模拟数据生成
// 修改后的模拟数据生成方法
// const generateMockOrders = () => {
//   const statusOptions = ['pending', 'shipped', 'delivered', 'completed', 'cancelled']
//   const productNames = ['智能手机', '无线耳机', '智能手表', '笔记本电脑', '平板电脑']
//   const specs = ['黑色 128G', '白色 256G', '蓝色 512G']
//
//   return Array.from({ length : 5 }, (_, i) => ({
//     id: `order_${i + 1}`,
//     orderNo: `NO${Math.floor(100000 + Math.random() * 900000)}`,
//     // 修正字段名：createTime -> create_time（根据后端字段）
//     create_time: new Date(Date.now() - i * 86400000).toISOString(),
//     status: statusOptions[i % 5],
//     deliveryAddress: `北京市海淀区中关村大街${i + 1}号`,
//     totalAmount: (Math.random() * 500 + 50).toFixed(2),
//     shippingFee: (Math.random() * 20).toFixed(2),
//     items: Array.from({ length: Math.floor(Math.random() * 3) + 1 }, (_, j) => ({
//       id: `item_${i}_${j}`,
//       name: productNames[j % 5],
//       image: 'https://via.placeholder.com/80x80.png?text=Product',
//       price: (Math.random() * 200 + 50).toFixed(2),
//       quantity: Math.floor(Math.random() * 3) + 1,
//       specification: specs[j % 3]
//     }))
//   }))
// }

onMounted(() => {
  fetchOrders()
})
</script>

<style scoped>
.order-container {
  height: 100vh;
  background: linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%);
}

.order-header {
  background: rgba(255, 255, 255, 0.95);
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.1);
}

.header-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  height: 100%;
}

.order-title {
  display: flex;
  align-items: center;
  gap: 15px;
}

.title-text {
  font-size: 20px;
  font-weight: 600;
  color: #303133;
}

.order-main {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

.filter-toolbar {
  display: flex;
  justify-content: space-between;
  margin-bottom: 20px;
  flex-wrap: wrap;
  gap: 15px;
}

.search-box {
  display: flex;
  gap: 10px;
}

.search-input {
  width: 250px;
}

.order-list {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.order-card {
  transition: all 0.3s;
  border-radius: 8px;
}

.order-card:hover {
  transform: translateY(-3px);
  box-shadow: 0 6px 18px rgba(0, 0, 0, 0.1);
}

.pending-order {
  border-left: 4px solid var(--el-color-danger);
}

.shipped-order {
  border-left: 4px solid var(--el-color-warning);
}

.delivered-order {
  border-left: 4px solid var(--el-color-primary);
}

.order-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 0;
}

.order-meta {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.order-no {
  font-weight: 600;
  color: var(--el-text-color-primary);
}

.order-time {
  font-size: 12px;
  color: var(--el-text-color-secondary);
}

.product-list {
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.product-item {
  display: flex;
  gap: 15px;
  padding: 10px;
  border-radius: 4px;
  cursor: pointer;
  transition: background-color 0.2s;
}

.product-item:hover {
  background-color: var(--el-fill-color-light);
}

.product-image {
  width: 80px;
  height: 80px;
  border-radius: 4px;
}

.product-info {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.product-name {
  margin: 0;
  font-size: 14px;
  color: var(--el-text-color-primary);
}

.product-spec {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
  color: var(--el-text-color-secondary);
}

.product-price {
  font-weight: 600;
  color: var(--el-color-danger);
}

.order-summary {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 0;
}

.delivery-info {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 14px;
}

.delivery-address {
  color: var(--el-text-color-primary);
}

.total-amount {
  font-size: 14px;
  color: var(--el-text-color-regular);
}

.amount {
  font-weight: 600;
  color: var(--el-color-danger);
  font-size: 18px;
}

.order-footer {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  padding-top: 10px;
}

.pagination {
  display: flex;
  justify-content: center;
  margin-top: 30px;
}

/* 响应式调整 */
@media (max-width: 768px) {
  .filter-toolbar {
    flex-direction: column;
  }

  .search-box {
    width: 100%;
  }

  .search-input {
    width: 100%;
  }
}
</style>