class HttpUtils {
    /**
     * 基础请求方法
     * @private
     */
    static async _request(config) {
        const {
            url,
            method = 'GET',
            data = null,
            headers = {},
            params = {},
            timeout = 8000
        } = config

        try {
            // 处理URL参数
            let finalUrl = url
            if (method.toUpperCase() === 'GET' && Object.keys(params).length) {
                const query = new URLSearchParams(params).toString()
                finalUrl += `${url.includes('?') ? '&' : '?'}${query}`
            }

            // 配置请求头
            const defaultHeaders = {
                'Content-Type': 'application/json',
                'Authorization': localStorage.getItem('token')
                    ? `Bearer ${localStorage.getItem('token')}`
                    : undefined
            }

            // 处理FormData类型
            let body = data
            if (data instanceof FormData) {
                delete defaultHeaders['Content-Type']
            } else if (data && method.toUpperCase() !== 'GET') {
                body = JSON.stringify(data)
            }

            // 创建控制器支持超时
            const controller = new AbortController()
            const timeoutId = setTimeout(() => controller.abort(), timeout)

            // 发送请求
            const response = await fetch(finalUrl, {
                method,
                headers: { ...defaultHeaders, ...headers },
                body,
                signal: controller.signal
            })
            clearTimeout(timeoutId)

            // 处理HTTP错误状态
            if (!response.ok) {
                const error = new Error(`HTTP错误 ${response.status}`)
                error.status = response.status
                error.data = await response.json().catch(() => null)
                throw error
            }

            // 解析响应数据
            return await response.json()
        } catch (error) {
            // 增强错误信息
            const errorMessage = error.name === 'AbortError'
                ? '请求超时'
                : error.message
            console.error(`请求失败: ${errorMessage}`, error)
            throw new Error(`网络请求失败: ${errorMessage}`)
        }
    }

    /**
     * GET请求
     * @param {string} url 请求地址
     * @param {Object} [config] 请求配置
     * @returns {Promise<any>}
     */
    static get(url, config = {}) {
        return this._request({
            url,
            method: 'GET',
            ...config
        })
    }

    /**
     * POST请求
     * @param {string} url 请求地址
     * @param {Object} [config] 请求配置
     * @returns {Promise<any>}
     */
    static post(url, config = {}) {
        return this._request({
            url,
            method: 'POST',
            ...config
        })
    }
}

export default HttpUtils