import { createRouter, createWebHistory } from 'vue-router';
import Home from '@/views/HomePage.vue';
import Login from '@/views/LoginPage.vue'
import Registry from '@/views/RegisteryPage.vue'
import Goods from '@/views/GoodsPage.vue'
import ShopCarPage from "@/views/ShopCarPage.vue";
import Store from "@/views/StoreView.vue"
import Admin from "@/views/AdminPage.vue"
import Order from "@/views/OrderPage.vue"
import Details from '@/views/ProductDetail.vue'
const routes = [
    { path: '/', name: 'Home', component: Home ,meta:{title:'ego 易购网'}},
    { path: '/login', name:'login',component:Login,meta:{title:'用户登录'} },
    { path: '/registry', name:'registry',component:Registry ,meta:{title:'用户注册'}},
    { path: '/goods', name:'goods',component:Goods ,meta:{title:'商品分类'}},
    { path: '/shopcar', name:'shopcar',component:ShopCarPage ,meta:{title:'我的购物车'}},
    { path: '/store', name:'store',component:Store,meta:{title:'后台：商店管理'}},
    { path: '/admin', name:'admin',component:Admin,meta:{title:'后台：管理页面'}},
    { path: '/order', name:'order',component:Order,meta:{title:'我的订单'}},
    { path: '/details', name:'details',component:Details,meta:{title:'商品详情'}},
];

// routers.beforeEach((to, from, next) => {
//     if (to.meta.title) {
//         document.title = to.meta.title;
//     }
//     next();
// });

const router = createRouter({
    history: createWebHistory(),
    routes
});

export default router;