<template>
  <el-form :model="form" :rules="rules" ref="formRef">
    <el-form-item prop="phone">
      <el-input
          v-model="form.phone"
          placeholder="请输入手机号"
          class="custom-input"
      >
        <template #prefix>
          <el-icon class="input-icon"><Iphone /></el-icon>
        </template>
      </el-input>
    </el-form-item>

    <el-form-item prop="password">
      <el-input
          v-model="form.password"
          type="password"
          placeholder="请输入密码"
          show-password
          class="custom-input"
      >
        <template #prefix>
          <el-icon class="input-icon"><Lock /></el-icon>
        </template>
      </el-input>
    </el-form-item>

    <el-form-item>
      <el-button
          type="primary"
          class="login-btn"
          :loading="loading"
          @click="submitForm"
      >
        {{ loading ? '登录中...' : '立即登录' }}
      </el-button>
    </el-form-item>
  </el-form>
</template>

<script setup>
import { ref } from 'vue'
import { ElMessage } from 'element-plus'
import { useRouter } from 'vue-router'
import {parseToken} from "@/Utils/auth";

const router = useRouter()
const form = ref({
  phone: '',
  password: ''
})
const formRef = ref(null)
const loading = ref(false)

const validatePhone = (rule, value, callback) => {
  if (!/^1[3-9]\d{9}$/.test(value)) {
    callback(new Error('手机号格式错误'))
  } else {
    callback()
  }
}

const validatePassword = (rule, value, callback) => {
  if (value.length < 8 || !/[a-zA-Z]/.test(value) || !/\d/.test(value)) {
    callback(new Error('密码需8位且包含字母和数字'))
  } else {
    callback()
  }
}

const rules = {
  phone: [{ validator: validatePhone, trigger: 'blur' }],
  password: [{ validator: validatePassword, trigger: 'blur' }]
}

const submitForm = async () => {
  try {
    await formRef.value.validate()
    loading.value = true

    const response = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/login`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        id:form.value.phone,
        pswd:form.value.password,
        isAdministrator: false
      })
    })

    const data = await response.json()
    localStorage.setItem("token",data.token)
    console.log('save token')
    if (response.status === 200) {
      const payload = parseToken(data.token)
      if (payload) {

        if ('user' === payload.role) {
          router.push('/')
        } else if ('admin' === payload.role ) {
          localStorage.setItem('adminId', payload.id)
          router.push('/admin')
        }
      }

      ElMessage.success('登录成功')
    } else {
      ElMessage.error(data.message || '登录失败')
    }
  } catch (error) {
    ElMessage.error(error.message || '网络请求失败')
  } finally {
    loading.value = false
  }
}
</script>

<style scoped>
.custom-input {
  margin-bottom: 24px;
}

.custom-input :deep(.el-input__inner) {
  height: 48px;
  border-radius: 8px;
  padding-left: 40px;
}

.input-icon {
  color: #c0c4cc;
  font-size: 18px;
  margin-left: 8px;
}

.login-btn {
  width: 100%;
  height: 48px;
  font-size: 16px;
  border-radius: 8px;
  transition: all 0.3s;
}

.login-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(64, 158, 255, 0.3);
}
</style>