import { ElMessage } from 'element-plus'

/**
 * 购物车工具类 - 仅处理加入购物车逻辑
 */
class CartUtils {
    /**
     * 添加商品到购物车
     * @param {string} goodsId - 商品ID (字符串类型)
     * @param {number} [quantity=1] - 商品数量，默认为1
     */
    static addToCart(goodsId, quantity = 1,name='') {
        const token = localStorage.getItem('token')
        const isLoggedIn = !!token
        let excludeItems = []
        if (isLoggedIn) {
            // excludeItems = this._addToTempCart(goodsId,quantity)
            excludeItems = this._addToUserCart(goodsId, quantity)
        } else {
            this._addToTempCart(goodsId, quantity)
        }

        ElMessage.success(`${name}已加入购物车` + (isLoggedIn ? '' : '(未登录)'))
        return excludeItems
    }

    /**
     * 添加到用户购物车(user_car)
     * @private
     */
    static _addToUserCart(goodsId, quantity) {
        let userCart = []
        const userCartStr = localStorage.getItem('user_car')

        if (userCartStr) {
            userCart = JSON.parse(userCartStr)
        }

        // 查找是否已存在该商品
        const existingItem = userCart.find(item => item.goods_id === goodsId)
        let excludeItems;
        if (existingItem) {
            // 存在则增加数量
            existingItem.quantity += quantity
        } else {
            // 不存在则添加新商品
            excludeItems = {goods_id:goodsId,quantity:quantity}
            userCart.push({
                goods_id: goodsId,
                quantity: quantity
            })
        }

        localStorage.setItem('user_car', JSON.stringify(userCart))
        return excludeItems
    }

    /**
     * 添加到临时购物车(temp_car)
     * @private
     */
    static _addToTempCart(goodsId, quantity) {
        let tempCart = []
        const tempCartStr = localStorage.getItem('temp_car')
        let excludeItems;
        if (tempCartStr) {
            tempCart = JSON.parse(tempCartStr)
        }

        // 查找是否已存在该商品
        const existingItem = tempCart.find(item => item.goods_id === goodsId)

        if (existingItem) {
            // 存在则增加数量
            excludeItems = {goods_id:goodsId,quantity:quantity}
            existingItem.quantity += quantity
        } else {
            // 不存在则添加新商品
            tempCart.push({
                goods_id: goodsId,
                quantity: quantity,
                selected:false
            })
        }

        localStorage.setItem('temp_car', JSON.stringify(tempCart))
        return excludeItems
    }
    /**
     * 获取当前用户的购物车数据（根据登录状态自动判断）
     * @returns {Array} 购物车商品数组
     */
    static getCart() {
        const isLoggedIn = !!localStorage.getItem('token')
        return isLoggedIn ? this.getUserCart() : this.getTempCart()
    }

    /**
     * 获取用户购物车数据(user_car)
     * @returns {Array} 用户购物车商品数组
     */
    static getUserCart() {
        return this._getCartDataByKey('user_car')
    }

    /**
     * 获取临时购物车数据(temp_car)
     * @returns {Array} 临时购物车商品数组
     */
    static getTempCart() {
        return this._getCartDataByKey('temp_car')
    }

    /**
     * 通用方法：根据存储键获取购物车数据
     * @private
     */
    static _getCartDataByKey(key) {
        try {
            const cartData = localStorage.getItem(key)
            return cartData ? JSON.parse(cartData) : []
        } catch (error) {
            console.error('购物车数据解析失败:', error)
            return []
        }
    }
    static clearCart(isLoggedIn) {
        if (isLoggedIn) {
            localStorage.removeItem('user_car')
            localStorage.removeItem('temp_car')
        } else {
            localStorage.removeItem('temp_car')
        }
    }
}

export default CartUtils