<template>
  <div class="login-container">
    <div class="login-box">
      <div class="login-header">
        <h1>欢迎登录</h1>
        <div class="role-switch">
          <el-button
              v-for="role in roles"
              :key="role.value"
              :type="currentRole === role.value ? 'primary' : ''"
              @click="switchRole(role.value)"
              class="role-btn"
          >
            {{ role.label }}
          </el-button>
        </div>
      </div>

      <component :is="currentComponent" class="login-component" />
    </div>
  </div>
</template>

<script setup>
import { ref, computed } from 'vue'
import UserLogin from '@/components/UserLogin.vue'
import AdminLogin from '@/components/AdminLogin.vue'
import MerchantLogin from '@/components/MerchantLogin.vue'

const roles = [
  { label: '用户登录', value: 'user', component: UserLogin },
  { label: '管理员登录', value: 'admin', component: AdminLogin },
  { label: '商家登录', value: 'merchant', component: MerchantLogin }
]

const currentRole = ref('user')

const currentComponent = computed(() => {
  return roles.find(r => r.value === currentRole.value).component
})

const switchRole = (role) => {
  currentRole.value = role
}
</script>

<style scoped>
.login-container {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  background: linear-gradient(135deg, #f0f2f5 0%, #d1d9e6 100%);
}

.login-box {
  width: 420px;
  padding: 40px;
  background: rgba(255, 255, 255, 0.96);
  border-radius: 16px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
  backdrop-filter: blur(8px);
}

.login-header {
  text-align: center;
  margin-bottom: 30px;
}

.login-header h1 {
  color: #303133;
  font-size: 24px;
  margin-bottom: 16px;
  font-weight: 600;
}

.role-switch {
  display: flex;
  gap: 12px;
  justify-content: center;
  margin-top: 20px;
}

.role-btn {
  border-radius: 8px;
  padding: 10px 20px;
  transition: all 0.3s;
}

.login-component {
  margin-top: 24px;
}
</style>

<style scoped>
.custom-input {
  margin-bottom: 24px;
}

.custom-input :deep(.el-input__inner) {
