<template>
  <div class="product-detail-container">
    <el-row :gutter="20">
      <!-- 商品图片展示 -->
      <el-col :span="12">
        <el-image
            :src="product.image"
            :preview-src-list="[product.image]"
            fit="contain"
            class="main-image"
        />
        <div class="image-thumbnails" v-if="product.images && product.images.length > 1">
          <el-image
              v-for="(img, index) in product.images"
              :key="index"
              :src="img"
              fit="cover"
              class="thumbnail"
              @click="currentImage = img"
          />
        </div>
      </el-col>

      <!-- 商品信息 -->
      <el-col :span="12">
        <h2 class="product-title">{{ product.name }}</h2>

        <div class="product-meta">
          <div class="price-section">
            <span class="current-price">¥{{ product.price }}</span>
            <span class="original-price" v-if="product.originalPrice">¥{{ product.originalPrice }}</span>
            <el-tag type="danger" size="small" v-if="product.discount">
              {{ product.discount }}折
            </el-tag>
          </div>

          <div class="sales-info">
            <span>销量: {{ product.sales || 0 }}</span>
            <span>库存: {{ product.quantity || 0 }}</span>
            <span>收藏: {{ product.favorites || 0 }}</span>
          </div>
        </div>

        <el-divider />

        <!-- 商品规格 -->
        <div class="product-spec" v-if="product.specifications">
          <h3>规格选择</h3>
          <div class="spec-options">
            <el-radio-group v-model="selectedSpec">
              <el-radio
                  v-for="spec in product.specifications"
                  :key="spec.value"
                  :label="spec.value"
                  border
              >
                {{ spec.label }}
              </el-radio>
            </el-radio-group>
          </div>
        </div>

        <!-- 购买数量 -->
        <div class="quantity-selector">
          <h3>购买数量</h3>
          <el-input-number
              v-model="quantity"
              :min="1"
              :max="product.quantity || 999"
              size="large"
          />
        </div>

        <el-divider />

        <!-- 操作按钮 -->
        <div class="action-buttons">
          <el-button type="danger" size="large" @click="addToCart">
            <el-icon><ShoppingCart /></el-icon>
            加入购物车
          </el-button>
          <el-button type="primary" size="large" @click="buyNow">
            立即购买
          </el-button>
          <el-button type="info" size="large" plain @click="addToFavorites">
            <el-icon><Star /></el-icon>
            收藏
          </el-button>
        </div>
      </el-col>
    </el-row>

    <!-- 商品详情描述 -->
    <div class="product-description">
      <el-tabs v-model="activeTab">
        <el-tab-pane label="商品详情" name="details">
          <div v-html="product.description"></div>
          <div class="detail-images" v-if="product.detailImages">
            <el-image
                v-for="(img, index) in product.detailImages"
                :key="index"
                :src="img"
                fit="contain"
                class="desc-image"
            />
          </div>
        </el-tab-pane>
        <el-tab-pane label="规格参数" name="specs">
          <el-table :data="product.specParams" border size="small">
            <el-table-column prop="name" label="参数名称" width="150" />
            <el-table-column prop="value" label="参数值" />
          </el-table>
        </el-tab-pane>
        <el-tab-pane label="售后保障" name="service">
          <div class="service-info">
            <h3>正品保障</h3>
            <p>本店所有商品均为正品，假一赔十</p>

            <h3>七天无理由退换</h3>
            <p>自收到商品之日起7天内可无理由退换货</p>

            <h3>运费说明</h3>
            <p>满99元包邮，不足99元收取10元运费</p>
          </div>
        </el-tab-pane>
      </el-tabs>
    </div>
  </div>
</template>

<script setup>
import { ref } from 'vue'
import { ShoppingCart, Star } from '@element-plus/icons-vue'
import {ElMessage} from "element-plus";

// eslint-disable-next-line no-undef
const props = defineProps({
  product: {
    type: Object,
    required: true,
    default: () => ({
      id: '',
      name: '',
      price: 0,
      image: '',
      quantity: 0,
      description: '',
      specifications: [],
      detailImages: []
    })
  }
})

// 组件状态
const activeTab = ref('details')
const selectedSpec = ref('')
const quantity = ref(1)
const currentImage = ref(props.product.image)

// 操作方法
const addToCart = () => {
  ElMessage.success('已加入购物车')
  // 实际加入购物车逻辑
}

const buyNow = () => {
  ElMessage.success('跳转到结算页面')
  // 实际购买逻辑
}

const addToFavorites = () => {
  ElMessage.success('已收藏商品')
  // 实际收藏逻辑
}
</script>

<style scoped>
.product-detail-container {
  padding: 20px;
  background-color: #fff;
  border-radius: 8px;
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.1);
}

.main-image {
  width: 100%;
  height: 400px;
  border: 1px solid #eee;
  border-radius: 8px;
  margin-bottom: 15px;
}

.image-thumbnails {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.thumbnail {
  width: 80px;
  height: 80px;
  border: 1px solid #ddd;
  border-radius: 4px;
  cursor: pointer;
  transition: border-color 0.3s;
}

.thumbnail:hover {
  border-color: var(--el-color-primary);
}

.product-title {
  font-size: 24px;
  margin-top: 0;
  color: var(--el-text-color-primary);
}

.price-section {
  display: flex;
  align-items: center;
  gap: 15px;
  margin: 15px 0;
}

.current-price {
  font-size: 28px;
  font-weight: bold;
  color: var(--el-color-danger);
}

.original-price {
  font-size: 16px;
  color: var(--el-text-color-secondary);
  text-decoration: line-through;
}

.sales-info {
  display: flex;
  gap: 20px;
  color: var(--el-text-color-secondary);
  font-size: 14px;
  margin-bottom: 20px;
}

.product-spec h3, .quantity-selector h3 {
  margin-top: 0;
  font-size: 16px;
  color: var(--el-text-color-regular);
  margin-bottom: 15px;
}

.spec-options {
  margin-bottom: 20px;
}

:deep(.el-radio.is-bordered) {
  margin-right: 10px;
  margin-bottom: 10px;
}

.quantity-selector {
  margin-bottom: 20px;
}

.action-buttons {
  display: flex;
  gap: 15px;
  margin-top: 30px;
}

.product-description {
  margin-top: 40px;
}

.detail-images {
  margin-top: 20px;
}

.desc-image {
  width: 100%;
  margin-bottom: 15px;
  border-radius: 4px;
}

.service-info h3 {
  color: var(--el-text-color-primary);
  margin-bottom: 8px;
}

.service-info p {
  color: var(--el-text-color-regular);
  margin-bottom: 15px;
}

/* 响应式调整 */
@media (max-width: 768px) {
  .main-image {
    height: 300px;
  }

  .product-title {
    font-size: 20px;
  }

  .current-price {
    font-size: 24px;
  }

  .action-buttons {
    flex-wrap: wrap;
  }

  .action-buttons .el-button {
    width: 100%;
    margin-bottom: 10px;
  }
}
</style>